204	    if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3) {
205	        if ([XPCarKeyHelp.shared localCarKeyIsVaild] && ![self isBLECardValid]) {
206	            DLogTagInfo(kBLECarKeyTag, @"钱包钥匙生效，没私有钥匙，需要静默激活");
207	            //静默激活
208	            @weakify(self);
209	            if (CTMediator.isSDK2ndCar) {
210	                [[XPVehicleSDK.shared.vehicleManager currentVehicle].digitalKeyManager createKeyWithSuccess:^{
211	                    @strongify(self);
212	                    DLogTagInfo(kBLECarKeyTag, @"3.0车型走SDK，创建钥匙成功");
213	                    [XPToast showMessage:@"已激活钥匙"];
214	                    [self refreshData];
215	                } failed:^(XPVehicleError * _Nonnull error) {
216	                    DLogTagInfo(kBLECarKeyTag, @"3.0车型走SDK，创建钥匙失败%@", error.description);
217	                    [XPToast showMessage:@"激活失败，请在有网环境重试"];
218	                }];
219	            } else {
220	                [[XPAPIRequestManager.sharedManager createBleKeyV3PrivateKey:CTMediator.vin deviceType:XPBLEKeyDeviceTypePhone] subscribeNext:^(Response * _Nullable x) {
221	                    if(x.isSuccess){
222	                        XPBLEKeyCard *card = [XPBLEKeyCard yy_modelWithJSON:x.data[@"keyInfo"]];
223	                        [XPBLEKeyManager.instance deleteCertKeyWithVin:CTMediator.vin];
224	                        [XPBLEHandlerManager.manager deleteMyBleKeyEvent];
225	                        [XPBLEKeyManager.instance saveIsCertKeyCreatedWithVin:CTMediator.vin isCreated:YES];
226	                        [self refreshData];
227	                        [NSNotificationCenter.defaultCenter postNotificationName:BLEKeyButtonUpdateNotification object:nil];
228	                        [XPToast showMessage:@"已激活钥匙"];
229	                        
