59	- (id)initWithCarControlStyle:(CarControlStyle)carControlStyle isParking:(BOOL)isParking {
60	    if (self = [super init]) {
61	        self.isParking = isParking;
62	        //控制模式
63	        self.carControlStyle = carControlStyle;
64	        // 初始状态
65	        self.operationType = CameraOperationTypeNone;
66	        
67	        if ([CTMediator isSDK2ndCar] && !self.isParking) {
68	            self.cameraManager = [XPVehicleExt createVehicleCameraManager:XPVehicleSDK.currentVehicle];
69	            @weakify(self);
70	            self.cameraSubscriber = [self.cameraManager.vehicleCameraStateChangedEvent on:^(id _Nonnull state) {
71	                @strongify(self);
72	                XPCameraStateChangedObject *cameraState = state;
73	                DLogTagInfo(kCameraTag, @"摄像头状态：%@", [state yy_modelToJSONString]);
74	                self.cameraInfo = [CameraInfo instanceFromCameraStateObject:cameraState];
75	                DLogTagInfo(kCameraTag, @"cameraInfo = %@", self.cameraInfo);
76	                if (self.cameraInfoChange) {
77	                    self.cameraInfoChange();
78	                }
79	            }];
80	            [self.cameraManager start];
81	        } else {
82	            // 先发心跳
83	            [self startHeartJumpt];
84	            // 查询状态
85	            [self checkStatus];
86	            [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleCameraOperation:) name:MQTTNotificationCameraOperationInfo object:nil];
87	            @weakify(self);
88	            [RACObserve(XPMQTTPublisher.sharedInstance, state).distinctUntilChanged subscribeNext:^(id _Nullable x) {
89	                @strongify(self);
90	                XPMQTTPublisherConnectionState state = [x intValue];
91	                if (state == XPMQTTPublisherConnectionStateConnected) {
92	                    [self hanleMQTTConnected];
93	                }
94	            }];
95	            [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(hanleMQTTConnected) name:MQTTNotificationConnectSuccess object:nil];
96	            [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(hanleWillEnterForeground) name:UIApplicationWillEnterForegroundNotification object:nil];
97	            [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(hanleDidEnterBackgroud) name:UIApplicationDidEnterBackgroundNotification object:nil];
98	        }
99	        
100	        
101	        @weakify(self);
102	        [[XPVehicleSDK.shared.vehicleManager.vehicleStateChangedEvent onImmediately:^(id _Nonnull obj) {
103	            @strongify(self)
104	            XPVehicleStateNotiObject * vehicleStateObj = obj;
105	            self.fullVehicleStateDict = vehicleStateObj.fullVehicleDict;
106	
107	        }] bind:self];
108	
109	    }
110	    return self;
111	}
