if ([CTMediator isSDK2ndCar]) {
    id<XPVehiclePresenter> currentVehicle = XPVehicleSDK.shared.vehicleManager.currentVehicle;
    if(!currentVehicle) return;
    XPPollingSelfCalibrationConfig *config = [XPPollingSelfCalibrationConfig new];
    [currentVehicle.digitalKeyManager.selfCalibration startWithConfig:config success:^(id<SelfCalibrationResultBaseProtocol> _Nonnull result) {
        id res = result;
        if ([result conformsToProtocol:@protocol(SelfCalibrationResultV2Protocol)]) {
            if (res) {
                [self handleStep2:nil txPowerArray:@[[res getResultMapWithDirection:BleVehicleDirectionFront]]];
            }
        }
        if ([result conformsToProtocol:@protocol(SelfCalibrationResultV3Protocol)]) {
            if (res) {
                [self handleStep2:nil txPowerArray:[res results]];
            }
        }
    } failure:^(NSError * _Nonnull error) {
        [self handleStep2:[NSError errorWithDomain:error.domain code:error.code userInfo:@{@"errorMsg": error.domain}] txPowerArray:@[]];
    }];
} else {
    [self.tool startRssiCalibration:BLEVehicleDirectionFRONT rssiArray:[PollingEffectDataManager.sharedManager getSelfCalibrationDirectionCoverMap:BLEVehicleDirectionFRONT] fininsh:^(NSError * _Nonnull error, NSArray * _Nonnull txpowerArray) {
        @strongify(self);
        [self handleStep2:error txPowerArray:txpowerArray];
    }];
}

