if(carInfo.isSDK2ndCar){
    id<XPVehiclePresenter> currentVehicle = XPVehicleSDK.currentVehicle;
    return [[[[[NSNotificationCenter.defaultCenter rac_addObserverForName:XPVehicleNotification.DigitalKeyStateChanged object:nil] filter:^BOOL(NSNotification * _Nullable value) {
        id<XPVehiclePresenter> vp = value.object;
        return [vp.vehiclePreference.vin isEqualToString:carInfo.vin];
    }] map:^id _Nullable(NSNotification * _Nullable value) {
        return value.object;
    }] startWith:currentVehicle] map:^id _Nullable(id<XPVehiclePresenter> _Nullable vp) {
        XPDigitalKey *sdkWatchKey = [vp.digitalKeyManager digitalKeyWithKeyCardType:XPKeyCardTypeAPPLE_WATCH];
        XPBLEKeyCard *cardModel = [XPBLEKeyCard yy_modelWithJSON:sdkWatchKey.bleKeyCard.toDict];
        XWCertKeyCardModel *watchCard = nil;
        if(cardModel && cardModel.status == XPBLEKeyCardStatusNormal){
            watchCard = [XWCertKeyCardModel new];
            watchCard.vin = cardModel.vin;
            watchCard.uid = cardModel.uid;
            watchCard.cardNo = cardModel.cardNo;
            watchCard.deviceId = cardModel.deviceId;
        }
        return RACTuplePack(carInfo, watchCard);
    }];
}

if(carInfo.hasBleAbility){
    XPDigitalKeyManageViewModel *viewModel = [XPBLEKeyManager.instance viewModelWithVin:carInfo.vin];
    return [viewModel.myCardListUpdateSignal map:^id _Nullable(NSArray<XPBLEKeyCard *> * _Nullable value) {
        XWCertKeyCardModel *watchCard = nil;
        for(XPBLEKeyCard *card in value){
            if(card.cardType == XPBLEKeyCardType_WatchCertKey && card.status == XPBLEKeyCardStatusNormal){
